import React, { useState } from "react";
import {
  Button,
  TextField,
  Typography,
  Box,
  Grid,
  Paper,
} from "@mui/material";

export default function DocumentUpload() {
  const [docs, setDocs] = useState({
    licenseNumber: "",
    rcNumber: "",
    insuranceNumber: "",
    licenseImage: null,
    rcImage: null,
    insuranceImage: null,
    aadharFront: null,
    aadharBack: null,
  });

  const handleFileChange = (e, field) => {
    setDocs({ ...docs, [field]: e.target.files[0] });
  };

  const handleInputChange = (e) => {
    setDocs({ ...docs, [e.target.name]: e.target.value });
  };

  const handleSubmit = () => {
    console.log("📌 Submitting documents:", docs);
  };

  return (
    <Box sx={{ display: "flex", justifyContent: "center", mt: 6 }}>
      <Paper
        elevation={3}
        sx={{ p: 4, width: "90%", maxWidth: 900, borderRadius: 3 }}
      >
        <Typography variant="h4" sx={{ fontWeight: "bold", mb: 4, textAlign: "center" }}>
          Upload Documents
        </Typography>

        <Grid container spacing={3}>
          {/* License */}
          <Grid item xs={12} sm={6}>
            <TextField
              fullWidth
              label="License Number"
              name="licenseNumber"
              value={docs.licenseNumber}
              onChange={handleInputChange}
            />
          </Grid>
          <Grid item xs={12} sm={6}>
            <Box sx={{ display: "flex", gap: 1, alignItems: "center" }}>
              <Button variant="outlined" component="label">
                Upload License
                <input hidden type="file" onChange={(e) => handleFileChange(e, "licenseImage")} />
              </Button>
              <Button variant="contained" color="secondary">
                Use Camera
              </Button>
              {docs.licenseImage && (
                <Typography variant="body2">{docs.licenseImage.name}</Typography>
              )}
            </Box>
          </Grid>

          {/* RC */}
          <Grid item xs={12} sm={6}>
            <TextField
              fullWidth
              label="RC Number"
              name="rcNumber"
              value={docs.rcNumber}
              onChange={handleInputChange}
            />
          </Grid>
          <Grid item xs={12} sm={6}>
            <Box sx={{ display: "flex", gap: 1, alignItems: "center" }}>
              <Button variant="outlined" component="label">
                Upload RC
                <input hidden type="file" onChange={(e) => handleFileChange(e, "rcImage")} />
              </Button>
              <Button variant="contained" color="secondary">
                Use Camera
              </Button>
              {docs.rcImage && (
                <Typography variant="body2">{docs.rcImage.name}</Typography>
              )}
            </Box>
          </Grid>

          {/* Insurance */}
          <Grid item xs={12} sm={6}>
            <TextField
              fullWidth
              label="Insurance Policy Number"
              name="insuranceNumber"
              value={docs.insuranceNumber}
              onChange={handleInputChange}
            />
          </Grid>
          <Grid item xs={12} sm={6}>
            <Box sx={{ display: "flex", gap: 1, alignItems: "center" }}>
              <Button variant="outlined" component="label">
                Upload Insurance
                <input hidden type="file" onChange={(e) => handleFileChange(e, "insuranceImage")} />
              </Button>
              <Button variant="contained" color="secondary">
                Use Camera
              </Button>
              {docs.insuranceImage && (
                <Typography variant="body2">{docs.insuranceImage.name}</Typography>
              )}
            </Box>
          </Grid>

          {/* Aadhar Front */}
          <Grid item xs={12} sm={6}>
            <Typography>Aadhar Card (Front)</Typography>
          </Grid>
          <Grid item xs={12} sm={6}>
            <Box sx={{ display: "flex", gap: 1, alignItems: "center" }}>
              <Button variant="outlined" component="label">
                Upload Front
                <input hidden type="file" onChange={(e) => handleFileChange(e, "aadharFront")} />
              </Button>
              <Button variant="contained" color="secondary">
                Use Camera
              </Button>
              {docs.aadharFront && (
                <Typography variant="body2">{docs.aadharFront.name}</Typography>
              )}
            </Box>
          </Grid>

          {/* Aadhar Back */}
          <Grid item xs={12} sm={6}>
            <Typography>Aadhar Card (Back)</Typography>
          </Grid>
          <Grid item xs={12} sm={6}>
            <Box sx={{ display: "flex", gap: 1, alignItems: "center" }}>
              <Button variant="outlined" component="label">
                Upload Back
                <input hidden type="file" onChange={(e) => handleFileChange(e, "aadharBack")} />
              </Button>
              <Button variant="contained" color="secondary">
                Use Camera
              </Button>
              {docs.aadharBack && (
                <Typography variant="body2">{docs.aadharBack.name}</Typography>
              )}
            </Box>
          </Grid>
        </Grid>

        <Box sx={{ mt: 4, textAlign: "center" }}>
          <Button
            variant="contained"
            sx={{ bgcolor: "black", color: "white", px: 4, py: 1.5 }}
            onClick={handleSubmit}
          >
            Submit Documents
          </Button>
        </Box>
      </Paper>
    </Box>
  );
}
